using Microsoft.AspNetCore.Http;
using TestProject.Models;
using TestProject.Services;

namespace TestProject.Tests.Controllers;

/// <summary>
/// Recording double for <see cref="IFileService"/>. Each method stashes the
/// arguments it was called with and either returns a configurable value or
/// throws a configurable exception, giving each test full control over the
/// service's behavior while keeping the double trivially inspectable.
/// </summary>
public sealed class FakeFileService : IFileService
{
    // ----- recorded inputs -----
    public string? BrowsePath;
    public string? SearchQuery;
    public string? SearchPath;
    public string? ResolvePath;
    public string? UploadDirPath;
    public IFormFile? UploadFile;
    public string? DeletePath;
    public MoveRequest? MoveRequest;
    public CopyRequest? CopyRequest;
    public string? CreateDirectoryPath;

    // ----- configurable outputs / faults -----
    public BrowseResultDto BrowseResult = new(string.Empty, null, Array.Empty<FileEntryDto>(), 0, 0, 0L);
    public SearchResultDto SearchResult = new(string.Empty, string.Empty, Array.Empty<FileEntryDto>());
    public string ResolvedPath = string.Empty;
    /// <summary>
    /// The stored relative path <see cref="UploadAsync"/> reports back to the
    /// caller. Mirrors the real <c>FileService.UploadAsync</c> return value so
    /// controller tests can assert the returned path is echoed verbatim.
    /// </summary>
    public string UploadedPath = string.Empty;
    public Exception? BrowseException;
    public Exception? SearchException;
    public Exception? ResolveException;
    public Exception? UploadException;
    public Exception? DeleteException;
    public Exception? MoveException;
    public Exception? CopyException;
    public Exception? CreateDirectoryException;

    public BrowseResultDto Browse(string relativePath)
    {
        BrowsePath = relativePath;
        if (BrowseException is not null) throw BrowseException;
        return BrowseResult;
    }

    public SearchResultDto Search(string query, string relativePath)
    {
        SearchQuery = query;
        SearchPath = relativePath;
        if (SearchException is not null) throw SearchException;
        return SearchResult;
    }

    public string ResolveFullPath(string relativePath)
    {
        ResolvePath = relativePath;
        if (ResolveException is not null) throw ResolveException;
        return ResolvedPath;
    }

    public Task<string> UploadAsync(string relativeDirPath, IFormFile file)
    {
        UploadDirPath = relativeDirPath;
        UploadFile = file;
        if (UploadException is not null) throw UploadException;
        return Task.FromResult(UploadedPath);
    }

    public void Delete(string relativePath)
    {
        DeletePath = relativePath;
        if (DeleteException is not null) throw DeleteException;
    }

    public void Move(MoveRequest request)
    {
        MoveRequest = request;
        if (MoveException is not null) throw MoveException;
    }

    public void Copy(CopyRequest request)
    {
        CopyRequest = request;
        if (CopyException is not null) throw CopyException;
    }

    public void CreateDirectory(string relativePath)
    {
        CreateDirectoryPath = relativePath;
        if (CreateDirectoryException is not null) throw CreateDirectoryException;
    }
}

using System.Reflection;
using Xunit;

namespace TestProject.Tests.TestHelpers;

/// <summary>
/// Reflection-based assertions that pin down the compiled contract of a
/// positional <c>record</c> type. Used by the <c>TestProject.Models</c> DTO
/// characterization tests so that splitting <c>Models/FileSystemModels.cs</c>
/// into per-DTO files is provably behavior-preserving: whichever file a type
/// ends up declared in, its namespace, sealed-record kind, primary-constructor
/// signature (parameter names, types, and order), and the set of public
/// init-only properties must remain byte-for-byte the same.
/// </summary>
internal static class RecordContract
{
    /// <summary>
    /// Asserts <paramref name="type"/> is a sealed, non-abstract, reference-type
    /// record living in <paramref name="expectedNamespace"/>.
    /// </summary>
    public static void AssertSealedRecordInNamespace(Type type, string expectedNamespace)
    {
        Assert.True(type.IsClass,
            $"{type.Name} must be a reference type (class), not a struct.");
        Assert.True(type.IsSealed,
            $"{type.Name} must be sealed (the DTOs are declared `sealed record`).");
        Assert.True(!type.IsAbstract,
            $"{type.Name} must not be abstract.");
        Assert.Equal(expectedNamespace, type.Namespace);
        Assert.True(IsRecord(type),
            $"{type.Name} must be a record (expected the synthesized copy method).");
    }

    /// <summary>
    /// Asserts <paramref name="type"/> declares exactly one public instance
    /// constructor whose parameters match <paramref name="expected"/> in name,
    /// type, and order, AND that each parameter is surfaced as a public
    /// property of the same name and type with no extra public properties.
    /// This pins the positional-record shape (constructor + auto-properties) so
    /// a moved DTO cannot silently gain, lose, reorder, rename, or retype a
    /// field. Note nullable-reference annotations (<c>string?</c> vs
    /// <c>string</c>) are not reflected in <see cref="Type"/> at runtime, so
    /// nullability is pinned separately via construction in the per-type tests.
    /// </summary>
    public static void AssertPositionalContract(
        Type type,
        params (string Name, Type Type)[] expected)
    {
        var constructors = type.GetConstructors();
        Assert.True(constructors.Length == 1,
            $"{type.Name} must declare exactly one public constructor (the " +
            "positional primary constructor); the protected copy constructor " +
            "synthesized for records must not be public. " +
            $"Found {constructors.Length}.");
        var primary = constructors[0];

        var parameters = primary.GetParameters();
        Assert.Equal(expected.Length, parameters.Length);
        for (var i = 0; i < expected.Length; i++)
        {
            Assert.True(
                parameters[i].Name == expected[i].Name &&
                parameters[i].ParameterType == expected[i].Type,
                $"{type.Name} constructor parameter #{i} must be " +
                $"{expected[i].Type.Name} {expected[i].Name}, but was " +
                $"{parameters[i].ParameterType.Name} {parameters[i].Name}.");
        }

        // Public instance properties: exactly the positional ones. The
        // synthesized protected `EqualityContract` property is excluded because
        // GetProperties() returns only public members.
        var properties = type.GetProperties();
        Assert.Equal(expected.Length, properties.Length);
        foreach (var (name, propertyType) in expected)
        {
            var property = type.GetProperty(name);
            Assert.NotNull(property);
            Assert.True(property!.CanRead, $"{type.Name}.{name} must have a getter.");
            Assert.True(property.CanWrite,
                $"{type.Name}.{name} must have an init/set accessor so `with` works.");
            Assert.Equal(propertyType, property.PropertyType);
        }
    }

    /// <summary>
    /// Asserts record value-equality semantics for two instances of the same
    /// type: the virtual <see cref="object.Equals(object)"/> in both
    /// directions, the generic <see cref="EqualityComparer{T}"/> comparer
    /// (which a record backs with its <c>IEquatable&lt;T&gt;</c>
    /// implementation), and — when equal — equal hash codes. Hash-code
    /// inequality is never asserted for non-equal instances (collisions are
    /// legal), but the hash must never differ for equal instances.
    /// </summary>
    public static void AssertEquality<T>(T a, T b, bool expectedEqual)
    {
        Assert.NotNull(a);
        Assert.NotNull(b);
        Assert.Equal(expectedEqual, a!.Equals(b));
        Assert.Equal(expectedEqual, b!.Equals(a));
        Assert.Equal(expectedEqual, EqualityComparer<T>.Default.Equals(a, b));
        if (expectedEqual)
        {
            Assert.Equal(a.GetHashCode(), b.GetHashCode());
        }
    }

    /// <summary>
    /// True when <paramref name="type"/> has the compiler-synthesized record
    /// copy method (<c>&lt;Clone&gt;$</c>), which only records and record
    /// structs emit. Searched across public and non-public instance members.
    /// </summary>
    private static bool IsRecord(Type type) =>
        type.GetMethod(
            "<Clone>$",
            BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic)
        is not null;
}

using System.Collections.Concurrent;
using System.Text;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.FileProviders;
using Microsoft.Extensions.Options;
using TestProject.Configuration;
using TestProject.Models;
using TestProject.Services;
using TestProject.Tests.TestHelpers;
using Xunit;

namespace TestProject.Tests.Services;

/// <summary>
/// Functional tests for <see cref="FileService"/>. Each test runs against a
/// unique temporary content root so that tests are fully independent and
/// never touch the real file system outside a scratch directory.
///
/// The service computes its home root once, at construction time, as
/// <c>Path.GetFullPath(Path.Combine(env.ContentRootPath, options.HomeDirectory))</c>.
/// Directory creation is deferred (lazy) until first use, so these tests
/// trigger an operation before asserting the directory exists on disk. Every
/// operation must funnel inputs through a path-safety check so that paths
/// escaping the home root throw <see cref="ArgumentException"/>.
/// </summary>
public class FileServiceTests : IDisposable
{
    private readonly string _contentRoot;

    public FileServiceTests()
    {
        _contentRoot = Directory.CreateTempSubdirectory("fs_test_").FullName;
    }

    public void Dispose()
    {
        try
        {
            Directory.Delete(_contentRoot, recursive: true);
        }
        catch
        {
            // Best effort cleanup; temp dirs may already be gone.
        }
    }

    // Builds a fresh service whose home directory lives under the per-test
    // content root. Returns the absolute, normalized root the service should
    // be treating as its sandbox.
    private (FileService service, string root) CreateService(string homeDirectory = "Home")
    {
        var env = new FakeWebHostEnvironment
        {
            ContentRootPath = _contentRoot
        };
        var options = Options.Create(new FileServiceOptions
        {
            HomeDirectory = homeDirectory
        });

        var service = new FileService(options, env);
        var root = Path.GetFullPath(Path.Combine(_contentRoot, homeDirectory));
        return (service, root);
    }

    // Builds the directory chain {baseDir}/d1/d2/.../d{levels}, creating every
    // intermediate directory along the way, and returns the deepest directory
    // path. `levels` is the number of nested directories beneath baseDir, so a
    // copy of baseDir recurses to depth == levels.
    private static string CreateNestedChain(string baseDir, int levels)
    {
        var current = baseDir;
        for (var i = 1; i <= levels; i++)
        {
            current = Path.Combine(current, $"d{i}");
        }
        Directory.CreateDirectory(current);
        return current;
    }

    // Creates a directory symbolic link, returning false when the host cannot
    // create one (e.g. Windows without the SeCreateSymbolicLinkPrivilege), so
    // the reparse-point-skipping tests can opt out cleanly instead of failing.
    private static bool TryCreateDirectorySymlink(string linkPath, string target)
    {
        try
        {
            return Directory.CreateSymbolicLink(linkPath, target) is not null;
        }
        catch (IOException) { return false; }
        catch (UnauthorizedAccessException) { return false; }
        catch (PlatformNotSupportedException) { return false; }
    }

    // File-symlink counterpart of TryCreateDirectorySymlink.
    private static bool TryCreateFileSymlink(string linkPath, string target)
    {
        try
        {
            return File.CreateSymbolicLink(linkPath, target) is not null;
        }
        catch (IOException) { return false; }
        catch (UnauthorizedAccessException) { return false; }
        catch (PlatformNotSupportedException) { return false; }
    }

    // =====================================================================
    // Constructor / root computation
    // =====================================================================

    [Fact]
    public void Constructor_CreatesRootDirectory_WhenItDoesNotExist()
    {
        var home = "BrandNewHome";
        var expectedRoot = Path.GetFullPath(Path.Combine(_contentRoot, home));

        Assert.False(Directory.Exists(expectedRoot));

        var (service, root) = CreateService(home);

        // Root creation is lazy: it happens on first use, not in the
        // constructor. Trigger initialization before asserting existence.
        service.ResolveFullPath("");

        Assert.True(Directory.Exists(root));
        Assert.Equal(expectedRoot, root);
    }

    [Fact]
    public void Constructor_SupportsNestedHomeDirectoryPath()
    {
        var home = "Data/Files";
        var expectedRoot = Path.GetFullPath(Path.Combine(_contentRoot, home));

        Assert.False(Directory.Exists(expectedRoot));

        var (service, root) = CreateService(home);

        // Root creation is lazy: trigger initialization (which must create
        // the full nested path) before asserting existence.
        service.ResolveFullPath("");

        Assert.Equal(expectedRoot, root);
        Assert.True(Directory.Exists(root));
    }

    [Fact]
    public void Constructor_NullHomeDirectory_DefaultsToHome()
    {
        var env = new FakeWebHostEnvironment { ContentRootPath = _contentRoot };
        var options = Options.Create(new FileServiceOptions { HomeDirectory = null! });

        var service = new FileService(options, env);

        var expected = Path.GetFullPath(Path.Combine(_contentRoot, "Home"));
        // ResolveFullPath triggers lazy initialization, materializing the
        // default "Home" directory before we assert its existence.
        Assert.Equal(expected, service.ResolveFullPath(""));
        Assert.True(Directory.Exists(expected));
    }

    // =====================================================================
    // Lazy initialization of the home root
    //
    // Two complementary flavors of test live here:
    //   1. The *negative* (lazy-specific) characterization below — the home
    //      directory must NOT exist on disk immediately after construction.
    //      Root creation is deferred to first use via the lazy value factory,
    //      matching the README's Configuration section ("created automatically
    //      on first use (lazily), ... so a misconfigured path surfaces on the
    //      first request rather than at startup").
    //   2. The *positive* (agnostic) characterization further down — the
    //      directory MUST exist after the first operation.
    // =====================================================================

    /// <summary>
    /// The home directory must NOT be materialized by the constructor. Root
    /// creation is deferred to first use via the lazy value factory, so
    /// constructing the service — equivalent to DI resolution at startup —
    /// has no filesystem side effects. This is the negative half of the lazy
    /// contract.
    /// </summary>
    [Fact]
    public void Constructor_DoesNotCreateRootDirectory_BeforeFirstUse()
    {
        var home = "EagerCheckFlat";
        var expectedRoot = Path.GetFullPath(Path.Combine(_contentRoot, home));

        Assert.False(Directory.Exists(expectedRoot));

        var (service, _) = CreateService(home);

        // No file-system operation has been invoked yet, so the home root
        // must not exist on disk. Constructing the service alone must not
        // touch the disk.
        Assert.False(Directory.Exists(expectedRoot));

        // Sanity check that the same root DOES get created on first use, so
        // this test cannot pass vacuously (e.g. due to an uncreatable path).
        service.ResolveFullPath("");
        Assert.True(Directory.Exists(expectedRoot));
    }

    /// <summary>
    /// A nested home directory (e.g. <c>"Data/Files"</c>) must not have any of
    /// its ancestor segments created by the constructor either. Lazy
    /// creation means neither the intermediate <c>Data</c> directory nor the
    /// leaf <c>Data/Files</c> exists until the first operation targets the
    /// root.
    /// </summary>
    [Fact]
    public void Constructor_DoesNotCreateNestedHomeDirectory_BeforeFirstUse()
    {
        var home = "EagerCheckNested/Deep";
        var parentSegment = Path.GetFullPath(Path.Combine(_contentRoot, "EagerCheckNested"));
        var expectedRoot = Path.GetFullPath(Path.Combine(_contentRoot, home));

        Assert.False(Directory.Exists(parentSegment));
        Assert.False(Directory.Exists(expectedRoot));

        var (service, _) = CreateService(home);

        // Neither the intermediate nor the leaf directory should exist yet.
        Assert.False(Directory.Exists(parentSegment));
        Assert.False(Directory.Exists(expectedRoot));

        // First use materializes the entire nested chain in one step.
        service.ResolveFullPath("");
        Assert.True(Directory.Exists(parentSegment));
        Assert.True(Directory.Exists(expectedRoot));
    }

    /// <summary>
    /// A misconfigured home directory (here, one containing an illegal null
    /// character) must NOT surface at construction time. The path is only
    /// resolved inside the lazy value factory, so the error is deferred to
    /// the first file-system operation that touches <c>Root</c>. The null
    /// byte is the only invalid-path character that
    /// <see cref="Path.GetFullPath"/> rejects on every platform (on Linux,
    /// characters like <c>&lt;&gt;</c> and <c>:</c> are legal), so it is used
    /// for cross-platform determinism.
    /// </summary>
    [Fact]
    public void Constructor_MisconfiguredHomeDirectory_DoesNotThrowUntilFirstUse()
    {
        var env = new FakeWebHostEnvironment { ContentRootPath = _contentRoot };
